# Debounce Function Implementation

Here's a robust TypeScript implementation with proper cleanup:

```typescript
function debounce<T extends (...args: any[]) => void>(
  fn: T,
  delay: number
): (...args: Parameters<T>) => void {
  let timeoutId: ReturnType<typeof setTimeout> | null = null;

  const debounced = (...args: Parameters<T>): void => {
    // Clear existing timer if one is pending
    if (timeoutId !== null) {
      clearTimeout(timeoutId);
    }

    // Set new timer
    timeoutId = setTimeout(() => {
      fn(...args);
      timeoutId = null;
    }, delay);
  };

  // Add cancel method for explicit cleanup
  (debounced as any).cancel = (): void => {
    if (timeoutId !== null) {
      clearTimeout(timeoutId);
      timeoutId = null;
    }
  };

  // Add flush method to invoke immediately
  (debounced as any).flush = (...args: Parameters<T>): void => {
    if (timeoutId !== null) {
      clearTimeout(timeoutId);
      timeoutId = null;
    }
    fn(...args);
  };

  return debounced;
}

export default debounce;
```

## Extended Version with Better Types

For a more type-safe API with utility methods:

```typescript
interface DebouncedFunction<T extends (...args: any[]) => void> {
  (...args: Parameters<T>): void;
  cancel(): void;
  flush(...args: Parameters<T>): void;
  isPending(): boolean;
}

function debounce<T extends (...args: any[]) => void>(
  fn: T,
  delay: number
): DebouncedFunction<T> {
  let timeoutId: ReturnType<typeof setTimeout> | null = null;

  const debounced = (...args: Parameters<T>): void => {
    if (timeoutId !== null) {
      clearTimeout(timeoutId);
    }

    timeoutId = setTimeout(() => {
      fn(...args);
      timeoutId = null;
    }, delay);
  };

  debounced.cancel = (): void => {
    if (timeoutId !== null) {
      clearTimeout(timeoutId);
      timeoutId = null;
    }
  };

  debounced.flush = (...args: Parameters<T>): void => {
    debounced.cancel();
    fn(...args);
  };

  debounced.isPending = (): boolean => timeoutId !== null;

  return debounced;
}

export default debounce;
```

## Usage Examples

```typescript
// Basic usage
const handleSearch = debounce((query: string) => {
  console.log(`Searching for: ${query}`);
}, 300);

// Simulate rapid calls
handleSearch("r");
handleSearch("re");
handleSearch("rea");
handleSearch("reac");
handleSearch("react");
// Only logs "Searching for: react" after 300ms

// With cancel
const debouncedSave = debounce((data: object) => {
  console.log("Saving:", data);
}, 500);

debouncedSave({ name: "John" });
debouncedSave.cancel(); // Cleanup, won't execute

// With flush
const debouncedAPI = debounce((url: string) => {
  console.log(`Fetching ${url}`);
}, 1000);

debouncedAPI("/api/users");
debouncedAPI("/api/posts");
debouncedAPI.flush("/api/posts"); // Execute immediately
// Logs "Fetching /api/posts" right away

// Check pending state
const debouncedClick = debounce(() => {
  console.log("Clicked!");
}, 200);

debouncedClick();
console.log(debouncedClick.isPending()); // true
setTimeout(() => {
  console.log(debouncedClick.isPending()); // false
}, 300);
```

## React Hook Integration

```typescript
import { useRef, useCallback, useEffect } from "react";

function useDebouncedCallback<T extends (...args: any[]) => void>(
  callback: T,
  delay: number
): ReturnType<typeof debounce<T>> {
  const debouncedRef = useRef(debounce(callback, delay));

  useEffect(() => {
    // Update the debounced function when callback changes
    debouncedRef.current = debounce(callback, delay);

    // Cleanup on unmount
    return () => {
      debouncedRef.current.cancel();
    };
  }, [callback, delay]);

  return useCallback((...args: Parameters<T>) => {
    debouncedRef.current(...args);
  }, []) as ReturnType<typeof debounce<T>>;
}

// Usage
function SearchComponent() {
  const handleSearch = useDebouncedCallback((query: string) => {
    console.log("Searching:", query);
  }, 300);

  return (
    <input
      onChange={(e) => handleSearch(e.target.value)}
      placeholder="Search..."
    />
  );
}
```

## Key Features

✅ **Type-safe**: Full TypeScript support with proper generic types  
✅ **Timer cleanup**: Clears stale timers on each call  
✅ **Cancel method**: Explicit cleanup for unmounting/disposal  
✅ **Flush method**: Force immediate execution  
✅ **Pending state**: Check if execution is pending  
✅ **No dependencies**: Pure vanilla TypeScript/JavaScript  
✅ **Memory efficient**: Single closure captures minimal state
